222→public actual fun Instant.until(other: Instant, unit: DateTimeUnit, timeZone: TimeZone): Long = try {
223→    val thisZdt = this.atZone(timeZone)
224→    val otherZdt = other.atZone(timeZone)
225→    when(unit) {
226→        is DateTimeUnit.TimeBased -> until(other, unit)
227→        is DateTimeUnit.DayBased -> (thisZdt.until(otherZdt, jtChronoUnit.DAYS) / unit.days).toLong()
228→        is DateTimeUnit.MonthBased -> (thisZdt.until(otherZdt, jtChronoUnit.MONTHS) / unit.months).toLong()
229→    }
230→} catch (e: ArithmeticException) {
231→    if (this < other) Long.MAX_VALUE else Long.MIN_VALUE
232→} catch (e: Throwable) {
233→    if (e.isJodaDateTimeException()) throw DateTimeArithmeticException(e) else throw e
